// The lookup takes BOTH. A bare venue key is a caption that fires on the wrong
// town; a pipe key with no town is a caption that never fires at all.
const venueLine = (venue, cityId) => {
  const note = VENUE_NOTES[`${venue}|${cityId}`]
  return note ? `${venue} \u00b7 ${note}` : venue
}

// ---------------------------------------------------------------------------
// THE SLATE — every game not played in your own town.
// ---------------------------------------------------------------------------
const MONTHS = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC']
const DAYS = ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT']

function fmt(iso) {
  const [y, m, d] = iso.split('-').map(Number)
  const dt = new Date(y, m - 1, d)
  return `${DAYS[dt.getDay()]} ${String(d).padStart(2, '0')} ${MONTHS[m - 1]}`
}

const today = () => new Date().toISOString().slice(0, 10)

export function awaySlate(teamId) {
  const team = teamById(teamId)
  if (!team) return []
  const now = today()

  return GAMES
    // your games...
    .filter(g => g.home === teamId || g.away === teamId)
    // ...that are NOT in your town. This is the whole rule.
    .filter(g => g.cityId !== team.cityId)
    // already-played games are excluded (locked, Session 1)
    .filter(g => g.date >= now)
    .sort((a, b) => a.date.localeCompare(b.date))
    .map((g) => {
      const oppId = g.home === teamId ? g.away : g.home
      const opp = teamById(oppId)
      const card = CITIES[g.cityId]
      return {
        id: `${teamId}-${g.date}-${g.cityId}`,
        opponent: opp ? opp.name : oppId,
        league: LEAGUE_LABEL[team.league] || team.league.toUpperCase(),
        rank: rankOf(team.league),
        // The lower third. Mode 1 knows who YOU are, so it reads "AT X".
        // Mode 2 does not, so it names both clubs. One field, both modes.
        fixture: `AT ${(opp ? opp.name : oppId).toUpperCase()}`,
        venue: venueLine(g.venue, g.cityId),
        cityId: g.cityId,
        city: card.city,
        state: card.state,
        stateCode: stateCode(card.state),
        lat: card.lat,
        lng: card.lng,
        facts: card.facts,
        todo: card.todo,
        // 🔴 S20. `date` is a LABEL — 'FRI 17 JUL'. Sorting it puts Friday before
        // Monday before Saturday. The ISO date is the only thing that ORDERS.
        //   A FORMATTED FIELD IS NOT A KEY.
        iso: g.date,
        date: fmt(g.date)
      }
    })
}

// TOWNS --------------------------------------------------------------------
// THE WHEEL'S UNIT IS THE TOWN, NOT THE FIXTURE.
// A slate can visit the same city twice — the Cardinals and the Chiefs both
// play in Los Angeles twice; the Browns are in New York twice; the Jaguars are
// in London twice. Two identical slices would break the wheel: you could not
// tell which one won, and a near-miss on a town you were also going to hit
// anyway is not a near-miss at all.
//
// So the slate is grouped into towns. Each town is ONE candidate, however many
// games it holds. Every town on the slate has exactly the same shot as every
// other — and if fate lands on a town with two dates, it takes one of them.
export function townsFromSlate(games) {
  const byCity = new Map()
  games.forEach(g => {
    if (!byCity.has(g.cityId)) byCity.set(g.cityId, [])
    byCity.get(g.cityId).push(g)
  })
  return [...byCity.values()] // an array of towns; each town is its list of games
}

// The wheel's fixed slice count. The deal exists to feed it exactly this many.
export const SLICES = 9

// ---------------------------------------------------------------------------
// MODE 2 — OPEN ROAD

// ---------------------------------------------------------------------------
// 🔴 S20. THREE THINGS THE GAME OBJECT KNEW AND NEVER SAID.
// ---------------------------------------------------------------------------
// 1. WHAT SPORT IS THIS. "IOWA CUBS AT TOLEDO MUD HENS" tells you two club names
//    and leaves you to guess the game. The league was one lookup away the whole
//    time.
//
// 2. WHAT ELSE IS ON. The wheel deals TOWNS (S7). The result screen then pretended
//    a town had exactly one game — because oneOf() picked one AT RANDOM and threw
//    the rest away in silence. In a Thursday-to-Monday window only THIRTEEN of
//    eighty-one towns have a single game; sixty-eight have three or more, and
//    Anaheim has TEN. The app could hand you a Low-A game twenty-eight miles out
//    while the Angels were at home that same night, and never mention it.
//
//      FATE PICKS THE TOWN. IT DOES NOT PICK YOUR TUESDAY.
//
//    The town is the trip; the game is the excuse (S8). Which game you go to is a
//    travel decision, and the app had been making it for you, with a coin.
//
// 3. WHERE THAT TOWN IS. `state: 'Ohio'` on the card; 'OH' on a sign.
// ---------------------------------------------------------------------------
const LEAGUE_LABEL = {
  nfl: 'NFL', nhl: 'NHL', nba: 'NBA', mlb: 'MLB', milb: 'MiLB',
  mls: 'MLS', uslc: 'USL-C', usl1: 'USL-1'
}
// Which game is a town's HEADLINE. Not a coin flip. Unknown leagues sort last
// rather than sorting FIRST, which is what `undefined` would have done.
const LEAGUE_RANK = { nfl: 1, nhl: 2, nba: 3, mlb: 4, mls: 5, uslc: 6, usl1: 7, milb: 8 }
const rankOf = (lg) => LEAGUE_RANK[lg] || 99

// Every state on the 158 cards, read off the file — not typed from memory (S11).
// Canada carries the country too; a Manitoban is not going to guess "MB".
const STATE_CODES = {
  'Alabama': 'AL', 'Arizona': 'AZ', 'Arkansas': 'AR', 'California': 'CA',
  'Colorado': 'CO', 'Connecticut': 'CT', 'District of Columbia': 'DC',
  'Florida': 'FL', 'Georgia': 'GA', 'Idaho': 'ID', 'Illinois': 'IL',
  'Indiana': 'IN', 'Iowa': 'IA', 'Kansas': 'KS', 'Kentucky': 'KY',
  'Louisiana': 'LA', 'Maine': 'ME', 'Maryland': 'MD', 'Massachusetts': 'MA',
  'Michigan': 'MI', 'Minnesota': 'MN', 'Mississippi': 'MS', 'Missouri': 'MO',
  'Nebraska': 'NE', 'Nevada': 'NV', 'New Hampshire': 'NH', 'New Jersey': 'NJ',
  'New Mexico': 'NM', 'New York': 'NY', 'North Carolina': 'NC', 'Ohio': 'OH',
  'Oklahoma': 'OK', 'Oregon': 'OR', 'Pennsylvania': 'PA', 'Rhode Island': 'RI',
  'South Carolina': 'SC', 'Tennessee': 'TN', 'Texas': 'TX', 'Utah': 'UT',
  'Virginia': 'VA', 'Washington': 'WA', 'Wisconsin': 'WI',
  'Alberta, Canada': 'AB, CAN', 'British Columbia, Canada': 'BC, CAN',
  'Manitoba, Canada': 'MB, CAN', 'Ontario, Canada': 'ON, CAN',
  'Quebec, Canada': 'QC, CAN'
}
// A state we do not know comes back UNCHANGED. It never comes back wrong, and it
// never comes back blank. (London reads "United Kingdom", which is correct.)
export const stateCode = (s) => STATE_CODES[s] || s

// A TOWN, not a game. Folds every game on in that town, inside your window, into
// the ONE object the wheel and the result screen already know how to read.
export function townObject(games) {
  const byDate = [...games].sort((a, b) =>
    a.iso.localeCompare(b.iso) || a.rank - b.rank)
  const head = [...games].sort((a, b) =>
    a.rank - b.rank || a.iso.localeCompare(b.iso))[0]
  return {
    ...head,
    games: byDate.map(g => ({
      league: g.league, fixture: g.fixture, venue: g.venue,
      iso: g.iso, date: g.date
    }))
  }
}

// ---------------------------------------------------------------------------
// You do not choose a team. You choose a WINDOW. Fate does the rest.
//
// 🔴 S20 KILLED "A WEEKEND IS ITS SATURDAY".
// That rule was written for the machine's convenience, not for a traveller. If
// you are on the ground THURSDAY TO MONDAY, a Thursday night in Toledo IS the
// trip. The old model threw those games away — and with them most of MiLB, MLB
// and the USLs, all of which play six nights a week.
//
//   MODE 2 IS A TRAVELLER FRAMING A TRIP. The input is a DATE RANGE.
//
// THE MINIMUM VIABLE MODE 2 IS STILL A DATE PICKER AND NOTHING ELSE (S17). No
// city-size filter, no region, no sport toggles. Every other knob is a
// NARROWING feature, and narrowing is the opposite of the promise.
//
// AND NO COUNTS ON THE SCREEN. The old picker listed fourteen weekends with the
// number of towns beside each, which invited you to SHOP — and telling you the
// odds before the spin is the opposite of a roulette wheel (S4). The count now
// does exactly one job: it GATES the button. It never ranks your calendar.
//
// THE POOL IS US + CANADA (S18, Jake's call). Nine cards carry `intl: true` and
// Mode 2 filters them out. MODE 1 KEEPS THEM: if you CHOSE the Jaguars, London
// is the prize. If all you said was "I'm free that week", fate does not get to
// book you Melbourne.
//
// ⚠️ It is a KEY ON THE CARD, never a coordinate box. `lat >= 24` cleanly
// separates Mexico City from Miami and silently calls HONOLULU international.
// A box that decides is a fallback (S18).
// ---------------------------------------------------------------------------
const inPool = (cityId) => {
  const c = CITIES[cityId]
  return !!c && c.intl !== true
}

const addDay = (iso, n = 1) => {
  const [y, m, d] = iso.split('-').map(Number)
  const dt = new Date(y, m - 1, d + n)
  return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}-${String(dt.getDate()).padStart(2, '0')}`
}

// The calendar cannot open on a month with nothing in it, and cannot scroll past
// the last game we hold. Both ends come off the DATA, never off a constant.
export function dateBounds() {
  const now = today()
  let max = now
  GAMES.forEach(g => { if (g.date > max && inPool(g.cityId)) max = g.date })
  return { min: now, max }
}

// "THU 16 – MON 20 JULY". One day reads "SAT 18 JULY".
export function rangeLabel(from, to) {
  const [, m1, d1] = from.split('-').map(Number)
  const [, m2, d2] = to.split('-').map(Number)
  const day = (iso) => {
    const [y, m, d] = iso.split('-').map(Number)
    return DAYS[new Date(y, m - 1, d).getDay()]
  }
  if (from === to) return `${day(from)} ${d1} ${MONTHS[m1 - 1]}`
  return m1 === m2
    ? `${day(from)} ${d1} \u2013 ${day(to)} ${d2} ${MONTHS[m1 - 1]}`
    : `${day(from)} ${d1} ${MONTHS[m1 - 1]} \u2013 ${day(to)} ${d2} ${MONTHS[m2 - 1]}`
}

// The number of TOWNS in play across a window — the unit is the town, not the
// fixture (S7). This exists ONLY to gate the button. It is never rendered.
export function townsInRange(from, to) {
  const t = new Set()
  GAMES.forEach(g => {
    if (g.date >= from && g.date <= to && inPool(g.cityId)) t.add(g.cityId)
  })
  return t.size
}

// The same game-object contract as awaySlate. The wheel, the deal-map and the
// result screen cannot tell the two modes apart, and that is the point.
export function rangeSlate(from, to) {
  return GAMES
    .filter(g => g.date >= from && g.date <= to && inPool(g.cityId))
    .sort((a, b) => a.date.localeCompare(b.date))
    .map(g => {
      const home = teamById(g.home)
      const away = teamById(g.away)
      const card = CITIES[g.cityId]
      return {
        id: `${from}-${to}-${g.date}-${g.cityId}-${g.home}-${g.away}`,
        opponent: home ? home.name : g.home,
        league: home ? (LEAGUE_LABEL[home.league] || home.league.toUpperCase()) : '',
        rank: home ? rankOf(home.league) : 99,
        fixture: `${(away ? away.name : g.away).toUpperCase()} AT ${(home ? home.name : g.home).toUpperCase()}`,
        venue: venueLine(g.venue, g.cityId),
        cityId: g.cityId,
        city: card.city,
        state: card.state,
        stateCode: stateCode(card.state),
        lat: card.lat,
        lng: card.lng,
        facts: card.facts,
        todo: card.todo,
        // 🔴 S20. `date` is a LABEL — 'FRI 17 JUL'. Sorting it puts Friday before
        // Monday before Saturday. The ISO date is the only thing that ORDERS.
        //   A FORMATTED FIELD IS NOT A KEY.
        iso: g.date,
        date: fmt(g.date)
      }
    })
}
